mapper.select:
SELECT 
FROM vso_sale_model_build_config t
WHERE t.row_valid = 1

    AND t.id = #{id}


    AND t.sale_code = #{saleCode}


    AND t.build_config_code = #{buildConfigCode}


    AND t.enable = #{enable}


    AND t.sort = #{sort}


    AND t.description = #{description}


    AND t.create_time = #{createTime}


    AND t.create_by = #{createBy}


    AND t.modify_time = #{modifyTime}


    AND t.modify_by = #{modifyBy}


    AND t.row_version = #{rowVersion}

ORDER BY t.sort ASC, t.id DESC

SELECT 
FROM vso_sale_model_build_config t
WHERE t.row_valid = 1

    AND t.sale_code = #{params.saleCode}


    AND t.build_config_code = #{params.buildConfigCode}


    AND t.enable = #{params.enable}


    and date_format(t.create_time,'%Y%m%d') >= date_format(#{params.beginTime},'%Y%m%d')


    and date_format(t.create_time,'%Y%m%d') <= date_format(#{params.endTime},'%Y%m%d')

ORDER BY t.sort ASC, t.id DESC

SELECT COUNT(*)
FROM vso_sale_model_build_config t
WHERE t.row_valid = 1

    AND t.sale_code = #{params.saleCode}


    AND t.build_config_code = #{params.buildConfigCode}


    AND t.enable = #{params.enable}

